# Generated by google (gemini-2.5-flash)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        text(name: 'BUILD_COMMANDS', defaultValue: '''
# Example for a Maven project:
# mvn clean install -DskipTests
# Example for a Node.js project:
# npm install
# npm run build
echo "No specific build commands provided. Defaulting to a simple echo."
'''.trim(), description: 'Enter shell commands for the build phase. These commands will be executed sequentially.')

        text(name: 'TEST_SCRIPTS', defaultValue: '''
# Example for a Maven project:
# mvn test
# Example for a Node.js project:
# npm test
echo "No specific test scripts provided. Defaulting to a simple echo."
'''.trim(), description: 'Enter shell commands for the test phase. These commands will be executed sequentially.')

        text(name: 'DEPLOY_STEPS', defaultValue: '''
# Example for deploying a JAR to a remote server:
# scp target/my-app.jar user@your-server:/opt/apps/
# ssh user@your-server "sudo systemctl restart my-app"
echo "No specific deployment steps provided. Defaulting to a simple echo."
'''.trim(), description: 'Enter shell commands for the deployment phase. These commands will be executed sequentially.')
    }

    stages {
        stage('Build') {
            steps {
                script {
                    if (params.BUILD_COMMANDS.trim()) {
                        echo "--- Executing Custom Build Commands ---"
                        sh params.BUILD_COMMANDS
                        echo "--- Build Stage Completed ---"
                    } else {
                        echo "BUILD_COMMANDS parameter is empty. Skipping Build stage."
                    }
                }
            }
        }

        stage('Test') {
            steps {
                script {
                    if (params.TEST_SCRIPTS.trim()) {
                        echo "--- Executing Custom Test Scripts ---"
                        sh params.TEST_SCRIPTS
                        echo "--- Test Stage Completed ---"
                    } else {
                        echo "TEST_SCRIPTS parameter is empty. Skipping Test stage."
                    }
                }
            }
        }

        stage('Deploy') {
            steps {
                script {
                    if (params.DEPLOY_STEPS.trim()) {
                        echo "--- Executing Custom Deployment Steps ---"
                        sh params.DEPLOY_STEPS
                        echo "--- Deploy Stage Completed ---"
                    } else {
                        echo "DEPLOY_STEPS parameter is empty. Skipping Deploy stage."
                    }
                }
            }
        }
    }
}